static const EmbeddedAsset ASSETS[] = {
    {"/gui/index.html", "text/html; charset=utf-8", asset_index_html, sizeof(asset_index_html)},
    {"/gui/style.css", "text/css; charset=utf-8", asset_style_css, sizeof(asset_style_css)},
    {"/gui/app.js", "application/javascript; charset=utf-8", asset_app_js, sizeof(asset_app_js)},
};
static constexpr size_t ASSET_COUNT = sizeof(ASSETS) / sizeof(ASSETS[0]);

// Lookup by URL path. Returns nullptr if not found.
inline const EmbeddedAsset* findAsset(const char* path) {
    // Root redirect
    if (path[0] == '/' && path[1] == '\0') path = "/gui/index.html";
    for (size_t i = 0; i < ASSET_COUNT; i++) {
        // Compare case-insensitive
        const char* a = ASSETS[i].path;
        const char* b = path;
        while (*a && *b) {
            char ca = *a >= 'A' && *a <= 'Z' ? *a + 32 : *a;
            char cb = *b >= 'A' && *b <= 'Z' ? *b + 32 : *b;
            if (ca != cb) break;
            a++; b++;
        }
        if (*a == '\0' && *b == '\0') return &ASSETS[i];
    }
    return nullptr;
}

